// ---------------------------------------------------------------------------
// Error-path checks (no fixture needed — pure structural)
// ---------------------------------------------------------------------------

#[test]
fn tensor_to_array1_rejects_2d_input() {
    let t = Tensor::from_storage(TensorStorage::cpu(vec![1.0_f64; 6]), vec![2, 3], false)
        .expect("build tensor");
    assert!(
        tensor_to_array1(&t).is_err(),
        "tensor_to_array1 must reject a 2-D tensor"
    );
}

#[test]
fn tensor_to_array2_rejects_1d_input() {
    let t = Tensor::from_storage(TensorStorage::cpu(vec![1.0_f64; 4]), vec![4], false)
        .expect("build tensor");
    assert!(
        tensor_to_array2(&t).is_err(),
        "tensor_to_array2 must reject a 1-D tensor"
    );
}

#[test]
fn tensor_to_array1_usize_rejects_negative() {
    let t = Tensor::from_storage(
        TensorStorage::cpu(vec![0.0_f64, 1.0, -1.0]),
        vec![3],
        false,
    )
    .expect("build tensor");
    assert!(
        tensor_to_array1_usize(&t).is_err(),
        "tensor_to_array1_usize must reject negative values"
    );
}

#[test]
fn tensor_to_array1_usize_rejects_nan() {
    let t = Tensor::from_storage(
        TensorStorage::cpu(vec![0.0_f64, f64::NAN]),
        vec![2],
        false,
    )
    .expect("build tensor");
    assert!(
        tensor_to_array1_usize(&t).is_err(),
        "tensor_to_array1_usize must reject NaN"
    );
}

// ---------------------------------------------------------------------------
// Round-trip identity: tensor → array → tensor must preserve all values.
// ---------------------------------------------------------------------------

#[test]
fn adapter_1d_round_trip_identity() {
    let file = load_fixtures();
    let f = find(&file, "adapter_tensor_to_array1");
    let input_flat = f.input_flat.as_ref().expect("input_flat");
    let shape = f.shape.as_ref().expect("shape");

    let t_in = Tensor::from_storage(
        TensorStorage::cpu(input_flat.clone()),
        shape.clone(),
        false,
    )
    .expect("build tensor");
    let arr = tensor_to_array1(&t_in).expect("to array");
    let t_out = array1_to_tensor(arr).expect("back to tensor");

    let actual = t_out.data().expect("data").to_vec();
    assert_close_f64(&actual, input_flat, 1e-15, "1d round-trip");
}

#[test]
fn adapter_2d_round_trip_identity() {
    let file = load_fixtures();
    let f = find(&file, "adapter_tensor_to_array2");
    let input_flat = f.input_flat.as_ref().expect("input_flat");
    let shape = f.shape.as_ref().expect("shape");

    let t_in = Tensor::from_storage(
        TensorStorage::cpu(input_flat.clone()),
        shape.clone(),
        false,
    )
    .expect("build tensor");
    let arr = tensor_to_array2(&t_in).expect("to array2");
    let t_out = array2_to_tensor(arr).expect("back to tensor");

    let actual = t_out.data().expect("data").to_vec();
    assert_close_f64(&actual, input_flat, 1e-15, "2d round-trip");
}
